{
  "patch_id": "2026-03-12-TA-PATCH-CONTROL-PANEL-JS-FIX-02",
  "title": "Fix app_main.js setView routing for control panel",
  "description": "Restore stable view switching in front app_main.js by replacing the broken setView() block. Includes patches view mapping and safe render branching.",
  "target": "server/static/js/front/app_main.js",
  "type": "replace_function",
  "function_name": "setView",
  "content": "function setView(view, symbol = null) {\n  const viewMap = {\n    dashboard: \"#view-dashboard\",\n    analysis: \"#view-analysis\",\n    coin: \"#view-coin\",\n    trades: \"#view-trades\",\n    decisions: \"#view-decisions\",\n    ops: \"#view-ops\",\n    patches: \"#view-patches\",\n    dossier: \"#view-dossier\",\n    settings: \"#view-settings\",\n  };\n\n  let nextView = String(view || \"\").trim();\n  if (!viewMap[nextView]) nextView = \"dashboard\";\n\n  const targetSelector = viewMap[nextView];\n  const targetNode = document.querySelector(targetSelector);\n\n  document.querySelectorAll(\".view\").forEach((el) => {\n    el.classList.remove(\"active\");\n    el.style.display = \"none\";\n  });\n\n  document.querySelectorAll(\"[data-view]\").forEach((el) => {\n    el.classList.remove(\"active\");\n    const parent = el.closest(\".nav-item\");\n    if (parent) parent.classList.remove(\"active\");\n  });\n\n  if (targetNode) {\n    targetNode.classList.add(\"active\");\n    targetNode.style.display = \"\";\n  } else {\n    const fallback = document.querySelector(\"#view-dashboard\");\n    if (fallback) {\n      fallback.classList.add(\"active\");\n      fallback.style.display = \"\";\n      nextView = \"dashboard\";\n    }\n  }\n\n  const nav = document.querySelector(`[data-view=\"${nextView}\"]`);\n  if (nav) {\n    nav.classList.add(\"active\");\n    const parent = nav.closest(\".nav-item\");\n    if (parent) parent.classList.add(\"active\");\n  }\n\n  try {\n    if (typeof state === \"object\" && state) {\n      state.view = nextView;\n      if (symbol) state.symbol = symbol;\n    }\n  } catch (e) {\n    console.warn(\"[setView] state sync skipped:\", e);\n  }\n\n  try {\n    const hash = symbol ? `#${nextView}:${symbol}` : `#${nextView}`;\n    if (location.hash !== hash) {\n      history.replaceState(null, \"\", hash);\n    }\n  } catch (e) {\n    console.warn(\"[setView] hash sync skipped:\", e);\n  }\n\n  try {\n    if (nextView === \"dashboard\") {\n      if (typeof renderDashboard === \"function\") renderDashboard();\n      return;\n    }\n\n    if (nextView === \"analysis\") {\n      if (typeof renderAnalysisView === \"function\") {\n        renderAnalysisView();\n      } else if (\n        typeof window !== \"undefined\" &&\n        window.AnalysisView &&\n        typeof window.AnalysisView.render === \"function\"\n      ) {\n        window.AnalysisView.render();\n      }\n      return;\n    }\n\n    if (nextView === \"coin\") {\n      if (symbol) {\n        try {\n          if (typeof state === \"object\" && state) state.symbol = symbol;\n        } catch (_) {}\n      }\n\n      if (typeof renderCoinView === \"function\") {\n        renderCoinView(symbol || (typeof state === \"object\" && state ? state.symbol : null));\n      } else if (typeof renderCoin === \"function\") {\n        renderCoin(symbol || (typeof state === \"object\" && state ? state.symbol : null));\n      }\n      return;\n    }\n\n    if (nextView === \"trades\") {\n      if (typeof renderTradesView === \"function\") renderTradesView();\n      return;\n    }\n\n    if (nextView === \"decisions\") {\n      if (typeof renderDecisionsView === \"function\") renderDecisionsView();\n      return;\n    }\n\n    if (nextView === \"ops\") {\n      if (typeof renderOpsReportView === \"function\") {\n        renderOpsReportView();\n      } else if (\n        typeof window !== \"undefined\" &&\n        window.OpsReportView &&\n        typeof window.OpsReportView.render === \"function\"\n      ) {\n        window.OpsReportView.render();\n      }\n      return;\n    }\n\n    if (nextView === \"patches\") {\n      if (typeof renderPatchView === \"function\") {\n        renderPatchView();\n      } else {\n        if (typeof loadPatchList === \"function\") loadPatchList();\n        if (typeof loadPatchHistory === \"function\") loadPatchHistory();\n      }\n      return;\n    }\n\n    if (nextView === \"dossier\") {\n      if (typeof renderDossierView === \"function\") {\n        renderDossierView();\n      } else if (\n        typeof window !== \"undefined\" &&\n        window.DossierView &&\n        typeof window.DossierView.render === \"function\"\n      ) {\n        window.DossierView.render();\n      }\n      return;\n    }\n\n    if (nextView === \"settings\") {\n      if (typeof renderSettingsView === \"function\") {\n        renderSettingsView();\n      } else if (\n        typeof window !== \"undefined\" &&\n        window.SettingsView &&\n        typeof window.SettingsView.render === \"function\"\n      ) {\n        window.SettingsView.render();\n      }\n      return;\n    }\n  } catch (e) {\n    console.error(\"[setView] render failed:\", nextView, e);\n  }\n}",
  "notes": [
    "Replace setView() only",
    "Restore patches mapping",
    "Normalize front menu/view switching",
    "Minimal invasive patch"
  ]
}
